public DefaultPrettyPrinter createInstance() {
    try {
        if (getClass().getMethod("createInstance").getDeclaringClass() != DefaultPrettyPrinter.class) {
            return new DefaultPrettyPrinter(this);
        }
    } catch (NoSuchMethodException e) {
        // This should never happen since we know the method exists
        throw new RuntimeException(e);
    }
    throw new IllegalStateException("Subclass does not override createInstance");
}

